mapper.sql:
SELECT ID, START_TIME, END_TIME, TIME_LENGTH, REMARK, CLOSE_REASON_CODE, CLOSE_REASON_NAME, EFFECT_SHIPVOYAGE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_DIS_CLOSE_SAIL
and TO_CHAR(START_TIME,'YYYY-MM-DD') >= #{beginTimes}
and TO_CHAR(END_TIME,'YYYY-MM-DD') <= #{endTimes}

mapper.select:
SELECT A.ID, A.START_TIME, A.END_TIME, A.TIME_LENGTH, A.CLOSE_REASON_CODE, A.CLOSE_REASON_NAME, A.EFFECT_SHIPVOYAGE, A.REMARK, A.STATUS, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, C.SHIP_NAME FROM T_DIS_CLOSE_SAIL A LEFT JOIN T_DIS_CLOSE_SAIL_SHIP B ON B.CLOSE_SAIL_ID = A.ID LEFT JOIN T_DIS_SHIPVOYAGE C ON C.ID = B.SHIPVOYAGE_ID
and TO_CHAR(A.START_TIME,'YYYY-MM-DD') >= #{beginTimes}
and TO_CHAR(A.END_TIME,'YYYY-MM-DD') <= #{endTimes}
and B.SHIPVOYAGE_ID = #{shipvoyageId}
and A.STATUS = #{status}
ORDER BY A.START_TIME DESC
